import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.L3mmv3XT.js";const g=JSON.parse('{"title":"Projets similaires et inspirations","description":"","frontmatter":{},"headers":[],"relativePath":"inspirations.md","filePath":"inspirations.md","lastUpdated":1783942993000}'),i={name:"inspirations.md"};function l(n,e,s,d,u,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="projets-similaires-et-inspirations" tabindex="-1">Projets similaires et inspirations <a class="header-anchor" href="#projets-similaires-et-inspirations" aria-label="Permalink to &quot;Projets similaires et inspirations&quot;">​</a></h1><p>Ce document rassemble les projets open source et commerciaux proches de <strong>NovelTrad 2.0</strong>. L&#39;objectif n&#39;est pas de tous les copier, mais d&#39;identifier les patterns, les forces et les opportunités d&#39;innovation pour notre architecture multi-agent de traduction littéraire.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>NovelTrad se positionne comme un <strong>Multi-Agent Literary Translation Framework</strong> — plus qu&#39;un simple traducteur EPUB, moins qu&#39;un CAT professionnel. Cette page aide à garder cette ligne claire.</p></div><hr><h2 id="table-recapitulative" tabindex="-1">Table récapitulative <a class="header-anchor" href="#table-recapitulative" aria-label="Permalink to &quot;Table récapitulative&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Projet</th><th>Type</th><th>Forces clés</th><th>Inspiration pour NovelTrad</th><th>Priorité d&#39;étude</th></tr></thead><tbody><tr><td><a href="https://github.com/oomol-lab/epub-translator" target="_blank" rel="noreferrer">epub-translator</a></td><td>Pipeline EPUB + IA</td><td>Traduction EPUB complète, affichage bilingue, multi-provider</td><td>Export EPUB, mode bilingue, UX lecteur</td><td>Must-study</td></tr><tr><td><a href="https://pypi.org/project/bbook-maker/" target="_blank" rel="noreferrer">bbook-maker</a></td><td>Outil CLI/Python</td><td>Multi-provider (OpenAI/Claude/Gemini/Ollama), EPUB bilingue</td><td>Gestion multi-modèles, simplicité</td><td>Inspiration</td></tr><tr><td><a href="https://github.com/combobulativedesigns/gptwntranslator" target="_blank" rel="noreferrer">gptwntranslator</a></td><td>Scraper + traducteur</td><td>Scraping web novels, EPUB automatique, pipeline end-to-end</td><td>MVP minimal, workflow &quot;scrape → translate → export&quot;</td><td>Inspiration</td></tr><tr><td><a href="https://docs.rs/crate/honya/latest/source/README.md" target="_blank" rel="noreferrer">honya</a></td><td>CLI/TUI Rust</td><td>Orchestrator / Translator / Reviewer, glossaire + personnages</td><td>Orchestration agents, boucle review → correction</td><td>Must-study</td></tr><tr><td><a href="https://www.sourcepulse.org/projects/16076583" target="_blank" rel="noreferrer">LaTeXTrans</a></td><td>Framework académique multi-agent</td><td>Parser / Translator / Validator / Summarizer / Terminology / Generator</td><td>QA agent, glossaire agent, validation pipeline</td><td>Must-study</td></tr><tr><td><a href="https://arxiv.org/abs/2405.11804" target="_blank" rel="noreferrer">TransAgents</a></td><td>Recherche multi-agent</td><td>Traduction littéraire longue, évaluation humaine + LLM</td><td>Cohérence stylistique, traduction de romans</td><td>Inspiration</td></tr><tr><td><a href="https://arxiv.org/abs/2508.17720" target="_blank" rel="noreferrer">RepoTransAgent</a></td><td>Recherche multi-agent</td><td>Repository-aware, RAG + correction + prompt dynamique</td><td>Mémoire globale du roman, contexte repository-aware</td><td>Inspiration</td></tr><tr><td><a href="https://github.com/Lifailon/multranslate" target="_blank" rel="noreferrer">multranslate</a></td><td>Comparateur de providers</td><td>Comparaison parallèle, détection langue, historique</td><td>Benchmark qualité, comparaison providers</td><td>Inspiration</td></tr><tr><td><a href="https://arxiv.org/abs/2403.02367" target="_blank" rel="noreferrer">adaptNMT</a></td><td>Framework NMT</td><td>UI training + eval, métriques intégrées</td><td>Dashboard qualité, scoring automatique</td><td>Inspiration</td></tr><tr><td><a href="https://useanything.com/" target="_blank" rel="noreferrer">AnythingLLM Desktop</a></td><td>App desktop LLM</td><td>Gestion modèles locaux, RAG, historique SQLite</td><td>Workspaces par roman, injection de contexte</td><td>Inspiration</td></tr><tr><td><a href="https://chatboxai.app/" target="_blank" rel="noreferrer">Chatbox</a></td><td>App desktop chat LLM</td><td>UI paramètres modèle par workspace</td><td>&quot;Workspaces&quot; par projet, paramètres modèle contextuels</td><td>Inspiration</td></tr><tr><td><a href="https://www.youtube.com/watch?v=r8xFzIkFWJU" target="_blank" rel="noreferrer">Sugoi Toolkit</a></td><td>Traducteur VN/LN offline</td><td>Découpage phrases, file d&#39;attente, affichage côte à côte</td><td>Chunking, queue, UI côte à côte</td><td>Inspiration</td></tr><tr><td><a href="https://github.com/bookfere/Ebook-Translator-Calibre" target="_blank" rel="noreferrer">Ebook Translator (Calibre)</a></td><td>Plugin Calibre</td><td>Parsing EPUB propre, préservation balises, recompilation</td><td>Parsing EPUB sans casser le markup</td><td>Must-study</td></tr><tr><td><a href="https://omegat.org/" target="_blank" rel="noreferrer">OmegaT</a></td><td>CAT open source</td><td>Glossaires, mémoires de traduction, dictionnaires locaux</td><td>Glossaire verrouillé, TM, cohérence forcée</td><td>Must-study</td></tr><tr><td><a href="https://www.reddit.com/r/machinetranslation/comments/1jvx963/i_found_it_too_hard_to_translate_web_novels_using/" target="_blank" rel="noreferrer">OpenNovel</a></td><td>Extension navigateur</td><td>Simplicité extrême, scraping, glossaire auto, chunking</td><td>Zéro configuration, chunking intelligent</td><td>Inspiration</td></tr><tr><td><a href="https://github.com/anantham/LexiconForge" target="_blank" rel="noreferrer">LexiconForge</a></td><td>Web App</td><td>Feedback utilisateur 👍/👎, comparateur versions, exports EPUB enrichis, footnotes culturelles</td><td>Système de feedback, comparateur source/brute/IA, exports enrichis</td><td>Inspiration</td></tr><tr><td><a href="https://github.com/Shirochi-stack/Glossarion" target="_blank" rel="noreferrer">Glossarion</a></td><td>GUI PySide6</td><td>40+ providers IA (incl. Ollama), glossaire robuste, EPUB/manga, gestion quotas</td><td>Gestion multi-modèles, terminologie verrouillée, UI riche</td><td>Must-study</td></tr><tr><td><a href="https://github.com/YuBing-link/noveltrans" target="_blank" rel="noreferrer">NovelTrans</a></td><td>SaaS / plateforme</td><td>Projet resumable par épisode, QA queue, glossary lock/conflict, RAG TM, workspaces</td><td>Structure projet par épisode, file d&#39;attente QA, termes forbidden/locked</td><td>Must-study</td></tr><tr><td><a href="https://github.com/hydropix/TranslateBooksWithLLMs" target="_blank" rel="noreferrer">TranslateBooksWithLLMs</a></td><td>Desktop App</td><td>Formats variés (EPUB, DOCX, SRT, TXT), préservation formatage, checkpoints, pas de limite taille</td><td>Reprise sur incident, robustesse formatage, pas de limite taille</td><td>Must-study</td></tr><tr><td><a href="https://github.com/Helsinki-NLP/OPUS-CAT" target="_blank" rel="noreferrer">OPUS-CAT</a></td><td>MT Engine + Plugins</td><td>Modèles NMT locaux Marian, offline, plugins Trados/memoQ</td><td>Option modèles NMT locaux pour confidentialité/performance</td><td>Inspiration</td></tr><tr><td><a href="https://gitlab.com/sansors/polyglotshelf" target="_blank" rel="noreferrer">PolyglotShelf</a></td><td>Service Docker + UI web + API REST</td><td>Traduction en masse EPUB/PDF/DOCX/TXT/SRT/MOBI/AZW3/FB2 via Ollama Cloud, file SQLite durable, merge incrémental, glossaires</td><td>Architecture Docker, gestion de file durable, merge incrémental de gros EPUB, API REST</td><td>Must-study</td></tr></tbody></table><hr><h2 id="projets-recents-identifies-deepseek-2" tabindex="-1">Projets récents identifiés (DeepSeek 2) <a class="header-anchor" href="#projets-recents-identifies-deepseek-2" aria-label="Permalink to &quot;Projets récents identifiés (DeepSeek 2)&quot;">​</a></h2><h3 id="polyglotshelf" tabindex="-1">PolyglotShelf <a class="header-anchor" href="#polyglotshelf" aria-label="Permalink to &quot;PolyglotShelf&quot;">​</a></h3><ul><li><strong>Type</strong> : Service Docker + UI web + API REST.</li><li><strong>Forces</strong> : traduction en masse de EPUB/PDF/DOCX/TXT/SRT/MOBI/AZW3/FB2 via Ollama Cloud, orchestrateur mince qui route vers TranslateBooksWithLLMs / Calibre / pdf2zh-next, file SQLite durable, merge incrémental des gros EPUB découpés par chapitre, glossaires CSV, API REST documentée (OpenAPI).</li><li><strong>Inspiration</strong> : <ul><li>architecture conteneurisée pour le déploiement serveur (v2.0+) ;</li><li>file d’attente SQLite durable et jobs qui survivent au redémarrage ;</li><li>merge incrémental des chapitres traduits pour les gros EPUB ;</li><li>gestion des glossaires via API ;</li><li>support de nombreux formats source au-delà de l’EPUB.</li></ul></li></ul><hr><h2 id="projets-epub-ia" tabindex="-1">Projets EPUB + IA <a class="header-anchor" href="#projets-epub-ia" aria-label="Permalink to &quot;Projets EPUB + IA&quot;">​</a></h2><h3 id="epub-translator" tabindex="-1">epub-translator <a class="header-anchor" href="#epub-translator" aria-label="Permalink to &quot;epub-translator&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : c&#39;est le pipeline EPUB le plus propre du moment.</li><li><strong>Points forts</strong> : traduction EPUB complète, affichage bilingue, LLM multi-provider.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>structurer l&#39;export EPUB en deux pistes (original + traduction)</li><li>garder la navigation par chapitre et les métadonnées</li><li>permettre un mode &quot;lecture bilingue&quot; dans la UI</li></ul></li></ul><h3 id="bbook-maker" tabindex="-1">bbook-maker <a class="header-anchor" href="#bbook-maker" aria-label="Permalink to &quot;bbook-maker&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : simplicité et support Ollama natif.</li><li><strong>Points forts</strong> : CLI minimal, EPUB bilingue, multi-provider.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>garder la config provider simple (URL + modèle + clé)</li><li>générer un EPUB côte à côte comme option d&#39;export</li></ul></li></ul><h3 id="gptwntranslator" tabindex="-1">gptwntranslator <a class="header-anchor" href="#gptwntranslator" aria-label="Permalink to &quot;gptwntranslator&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : c&#39;est le MVP le plus direct.</li><li><strong>Points forts</strong> : scraping web novels, génération EPUB automatique.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>le workflow idéal pour un nouvel utilisateur : source → traduction → EPUB</li><li>garder une version &quot;one-shot&quot; du pipeline pour les cas simples</li></ul></li></ul><hr><h2 id="projets-multi-agent" tabindex="-1">Projets multi-agent <a class="header-anchor" href="#projets-multi-agent" aria-label="Permalink to &quot;Projets multi-agent&quot;">​</a></h2><h3 id="honya" tabindex="-1">honya <a class="header-anchor" href="#honya" aria-label="Permalink to &quot;honya&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : architecture 3 agents très proche de NovelTrad.</li><li><strong>Agents</strong> : Orchestrator, Translator, Reviewer.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>séparer explicitement l&#39;orchestrateur des agents de travail</li><li>ajouter une boucle review → correction avant le QA final</li><li>garder le glossaire et les personnages dans le contexte de l&#39;orchestrateur</li></ul></li></ul><h3 id="latextrans" tabindex="-1">LaTeXTrans <a class="header-anchor" href="#latextrans" aria-label="Permalink to &quot;LaTeXTrans&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : c&#39;est notre idée, mais appliquée à des papers.</li><li><strong>Agents</strong> : Parser, Translator, Validator, Summarizer, Terminology, Generator.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>renommer nos agents selon des responsabilités très précises</li><li>ajouter un agent &quot;Summarizer&quot; qui maintient un résumé global du roman</li><li>formaliser le QA comme un validator indépendant</li></ul></li></ul><h3 id="transagents" tabindex="-1">TransAgents <a class="header-anchor" href="#transagents" aria-label="Permalink to &quot;TransAgents&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : traduction littéraire ultra-longue avec évaluation humaine.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>évaluer la cohérence stylistique sur plusieurs chapitres</li><li>permettre un mode &quot;évaluation humaine&quot; intégrée dans la UI</li><li>documenter les agents de relecture comme pairs</li></ul></li></ul><h3 id="repotransagent" tabindex="-1">RepoTransAgent <a class="header-anchor" href="#repotransagent" aria-label="Permalink to &quot;RepoTransAgent&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : RAG et contexte repository-aware.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>enrichir la mémoire globale du projet (lexique + chapitres traduits)</li><li>prompts dynamiques en fonction du contexte du chapitre</li><li>indexation sémantique des chapitres précédents</li></ul></li></ul><hr><h2 id="outils-tao-et-professionnels" tabindex="-1">Outils TAO et professionnels <a class="header-anchor" href="#outils-tao-et-professionnels" aria-label="Permalink to &quot;Outils TAO et professionnels&quot;">​</a></h2><h3 id="omegat" tabindex="-1">OmegaT <a class="header-anchor" href="#omegat" aria-label="Permalink to &quot;OmegaT&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : standard open source de la traduction assistée.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>glossaires avec termes verrouillés</li><li>mémoires de traduction au format TMX</li><li>segmentation fine au niveau phrase</li><li>interface côte à cible avec statut segment par segment</li></ul></li></ul><h3 id="plugins-calibre-ebook-translator" tabindex="-1">Plugins Calibre (Ebook Translator) <a class="header-anchor" href="#plugins-calibre-ebook-translator" aria-label="Permalink to &quot;Plugins Calibre (Ebook Translator)&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : Calibre domine la gestion d&#39;eBooks et utilise SQLite.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>parsing EPUB sans destruction du markup</li><li>recompilation fidèle du HTML</li><li>gestion des styles CSS et des métadonnées</li></ul></li></ul><hr><h2 id="apps-desktop-llm" tabindex="-1">Apps desktop LLM <a class="header-anchor" href="#apps-desktop-llm" aria-label="Permalink to &quot;Apps desktop LLM&quot;">​</a></h2><h3 id="anythingllm-desktop" tabindex="-1">AnythingLLM Desktop <a class="header-anchor" href="#anythingllm-desktop" aria-label="Permalink to &quot;AnythingLLM Desktop&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : Electron + LLM local + base de données.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>workspaces par projet (un workspace = un roman)</li><li>injection RAG dans le contexte</li><li>gestion de l&#39;historique dans SQLite</li></ul></li></ul><h3 id="chatbox" tabindex="-1">Chatbox <a class="header-anchor" href="#chatbox" aria-label="Permalink to &quot;Chatbox&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : UI très propre pour paramètres modèles.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>paramètres modèles par workspace/projet</li><li>temperature, context length, system prompts configurables</li><li>interface minimaliste pour les non-tech</li></ul></li></ul><hr><h2 id="communaute-et-vn-ln" tabindex="-1">Communauté et VN/LN <a class="header-anchor" href="#communaute-et-vn-ln" aria-label="Permalink to &quot;Communauté et VN/LN&quot;">​</a></h2><h3 id="sugoi-toolkit" tabindex="-1">Sugoi Toolkit <a class="header-anchor" href="#sugoi-toolkit" aria-label="Permalink to &quot;Sugoi Toolkit&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : outil communautaire pour Visual Novels et Light Novels.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>découpage intelligent des phrases</li><li>file d&#39;attente pour ne pas saturer le modèle local</li><li>affichage côte à côte original/traduction</li></ul></li></ul><h3 id="opennovel" tabindex="-1">OpenNovel <a class="header-anchor" href="#opennovel" aria-label="Permalink to &quot;OpenNovel&quot;">​</a></h3><ul><li><strong>Pourquoi regarder</strong> : extension navigateur très simple.</li><li><strong>Ce qu&#39;on peut en tirer</strong> : <ul><li>zéro configuration pour le premier lancement</li><li>scraping + glossaire automatique</li><li>chunking intelligent</li></ul></li></ul><hr><h2 id="projets-recents-identifies-deepseek-2-1" tabindex="-1">Projets récents identifiés (DeepSeek 2) <a class="header-anchor" href="#projets-recents-identifies-deepseek-2-1" aria-label="Permalink to &quot;Projets récents identifiés (DeepSeek 2)&quot;">​</a></h2><h3 id="lexiconforge" tabindex="-1">LexiconForge <a class="header-anchor" href="#lexiconforge" aria-label="Permalink to &quot;LexiconForge&quot;">​</a></h3><ul><li><strong>Type</strong> : Web App.</li><li><strong>Forces</strong> : feedback utilisateur 👍/👎, comparateur de versions (source vs brute vs fan vs IA), génération de footnotes culturelles, exports EPUB enrichis.</li><li><strong>Inspiration</strong> : <ul><li>ajouter un système de feedback sur les paragraphes traduits</li><li>comparateur de versions côte à côte</li><li>exports EPUB avec notes et métadonnées enrichies</li></ul></li></ul><h3 id="glossarion" tabindex="-1">Glossarion <a class="header-anchor" href="#glossarion" aria-label="Permalink to &quot;Glossarion&quot;">​</a></h3><ul><li><strong>Type</strong> : GUI PySide6.</li><li><strong>Forces</strong> : 40+ providers IA (incluant Ollama), traduction manga (OCR + YOLO), gestion avancée des clés API et quotas, glossaire robuste.</li><li><strong>Inspiration</strong> : <ul><li>gestion multi-modèles et multi-clés</li><li>terminologie verrouillée et gestion des conflits</li><li>UI riche pour le glossaire</li></ul></li></ul><h3 id="noveltrans" tabindex="-1">NovelTrans <a class="header-anchor" href="#noveltrans" aria-label="Permalink to &quot;NovelTrans&quot;">​</a></h3><ul><li><strong>Type</strong> : SaaS / plateforme.</li><li><strong>Forces</strong> : projet resumable par épisode, file d&#39;attente QA, extraction/mise à jour/conflits de glossaire, RAG translation memory, workspaces.</li><li><strong>Inspiration</strong> : <ul><li>structure de projet par épisode</li><li>file d&#39;attente QA pour erreurs de traduction</li><li>termes &quot;forbidden&quot; et &quot;locked&quot;</li></ul></li></ul><h3 id="translatebookswithllms" tabindex="-1">TranslateBooksWithLLMs <a class="header-anchor" href="#translatebookswithllms" aria-label="Permalink to &quot;TranslateBooksWithLLMs&quot;">​</a></h3><ul><li><strong>Type</strong> : Desktop App.</li><li><strong>Forces</strong> : formats variés (EPUB, DOCX, SRT, TXT), préservation parfaite du formatage, checkpoints, pas de limite de taille.</li><li><strong>Inspiration</strong> : <ul><li>fiabilité et reprise sur incident</li><li>préservation sans faille du formatage source</li></ul></li></ul><h3 id="opus-cat" tabindex="-1">OPUS-CAT <a class="header-anchor" href="#opus-cat" aria-label="Permalink to &quot;OPUS-CAT&quot;">​</a></h3><ul><li><strong>Type</strong> : MT Engine + Plugins.</li><li><strong>Forces</strong> : modèles NMT locaux Marian, offline, sécurisés, plugins Trados/memoQ.</li><li><strong>Inspiration</strong> : <ul><li>option modèles NMT locaux en plus d&#39;Ollama</li><li>cas d&#39;usage confidentialité accrue ou performance</li></ul></li></ul><hr><h2 id="projets-mentionnes-comme-concurrents-mais-non-retenus-comme-inspiration" tabindex="-1">Projets mentionnes comme concurrents mais non retenus comme inspiration <a class="header-anchor" href="#projets-mentionnes-comme-concurrents-mais-non-retenus-comme-inspiration" aria-label="Permalink to &quot;Projets mentionnes comme concurrents mais non retenus comme inspiration&quot;">​</a></h2><p>Ces outils ont ete identifies dans les retours externes comme comparables, mais leur architecture ou leur public cible est trop eloigne pour une reutilisation directe dans NovelTrad :</p><table tabindex="0"><thead><tr><th>Projet</th><th>Categorie</th><th>Pourquoi non retenu</th></tr></thead><tbody><tr><td><strong>NovelGenerator</strong></td><td>Generation assistee</td><td>Generation complete de romans, pas traduction.</td></tr><tr><td><strong>NovelForge</strong></td><td>Creation assistee</td><td>Knowledge graph + creation, scope different.</td></tr><tr><td><strong>GalTransl</strong></td><td>Traduction VN</td><td>Patch de Visual Novels, pas pipeline EPUB/roman.</td></tr><tr><td><strong>Chinese Novel Translator</strong></td><td>Reddit/MVP</td><td>Fonctionnalites deja couvertes par <code>gptwntranslator</code> / <code>OpenNovel</code>.</td></tr><tr><td><strong>clipboard-based translator pipeline</strong></td><td>Reddit/MVP</td><td>Queue/batch deja couverts par <code>Sugoi Toolkit</code>, <code>PolyglotShelf</code>, <code>NovelTrans</code>.</td></tr></tbody></table><hr><h2 id="ce-que-noveltrad-doit-retenir" tabindex="-1">Ce que NovelTrad doit retenir <a class="header-anchor" href="#ce-que-noveltrad-doit-retenir" aria-label="Permalink to &quot;Ce que NovelTrad doit retenir&quot;">​</a></h2><ol><li><strong>Multi-agent literary translation framework</strong> : notre catégorie est là. Il ne faut pas se comparer aux simples translate tools.</li><li><strong>Glossaire verrouillé + TM</strong> : la cohérence sur les longs romans est notre avantage.</li><li><strong>EPUB propre</strong> : parsing et recompilation sans casser le markup.</li><li><strong>Workspace par projet</strong> : chaque roman a son propre contexte, lexique, mémoire, paramètres modèle.</li><li><strong>Boucle review/QA</strong> : un agent reviewer + une file d&#39;attente QA avant validation.</li><li><strong>Checkpoints et resumability</strong> : reprise sur incident critique pour des romans longs.</li><li><strong>UI côte à côte</strong> : lecture bilingue et comparaison versions.</li><li><strong>Feedback utilisateur</strong> : 👍/👎 pour améliorer itérativement la qualité.</li><li><strong>Termes forbidden/locked</strong> : interdire certaines traductions comme le fait NovelTrans/Glossarion.</li><li><strong>Modèles NMT locaux</strong> : option future pour confidentialité ou performance.</li></ol><hr><h2 id="pistes-d-evolution-pour-noveltrad" tabindex="-1">Pistes d&#39;évolution pour NovelTrad <a class="header-anchor" href="#pistes-d-evolution-pour-noveltrad" aria-label="Permalink to &quot;Pistes d&#39;évolution pour NovelTrad&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Piste</th><th>Priorité</th><th>Projet inspirant</th></tr></thead><tbody><tr><td>Mode bilingue / côte à côte dans l&#39;UI</td><td>Should</td><td>epub-translator, Sugoi Toolkit, LexiconForge</td></tr><tr><td>Workspaces par roman avec paramètres modèles</td><td>Should</td><td>AnythingLLM, Chatbox, NovelTrans</td></tr><tr><td>Agent Reviewer + file d&#39;attente QA</td><td>Must</td><td>honya, NovelTrans, LaTeXTrans</td></tr><tr><td>Résumé global du roman pour cohérence</td><td>Should</td><td>LaTeXTrans, TransAgents</td></tr><tr><td>Parsing EPUB sans perte de balises</td><td>Must</td><td>Ebook Translator, Calibre</td></tr><tr><td>Checkpoints / reprise sur incident</td><td>Must</td><td>TranslateBooksWithLLMs, NovelTrans</td></tr><tr><td>Indexation sémantique des chapitres (RAG avancé)</td><td>Could</td><td>RepoTransAgent, NovelTrans</td></tr><tr><td>Dashboard qualité + benchmark providers</td><td>Could</td><td>multranslate, adaptNMT</td></tr><tr><td>Feedback utilisateur (👍/👎) sur les traductions</td><td>Could</td><td>LexiconForge</td></tr><tr><td>Termes &quot;forbidden&quot; et &quot;locked&quot;</td><td>Must</td><td>NovelTrans, Glossarion</td></tr><tr><td>Comparateur de versions source/brute/IA</td><td>Could</td><td>LexiconForge</td></tr><tr><td>Modèles NMT locaux</td><td>Could</td><td>OPUS-CAT</td></tr></tbody></table><hr><h2 id="references" tabindex="-1">Références <a class="header-anchor" href="#references" aria-label="Permalink to &quot;Références&quot;">​</a></h2><ul><li><a href="https://github.com/oomol-lab/epub-translator" target="_blank" rel="noreferrer">epub-translator — GitHub</a></li><li><a href="https://pypi.org/project/bbook-maker/" target="_blank" rel="noreferrer">bbook-maker — PyPI</a></li><li><a href="https://github.com/combobulativedesigns/gptwntranslator" target="_blank" rel="noreferrer">gptwntranslator — GitHub</a></li><li><a href="https://docs.rs/crate/honya/latest/source/README.md" target="_blank" rel="noreferrer">honya — Docs.rs</a></li><li><a href="https://www.sourcepulse.org/projects/16076583" target="_blank" rel="noreferrer">LaTeXTrans — SourcePulse</a></li><li><a href="https://arxiv.org/abs/2405.11804" target="_blank" rel="noreferrer">TransAgents — arXiv</a></li><li><a href="https://arxiv.org/abs/2508.17720" target="_blank" rel="noreferrer">RepoTransAgent — arXiv</a></li><li><a href="https://useanything.com/" target="_blank" rel="noreferrer">AnythingLLM</a></li><li><a href="https://chatboxai.app/" target="_blank" rel="noreferrer">Chatbox</a></li><li><a href="https://omegat.org/" target="_blank" rel="noreferrer">OmegaT</a></li><li><a href="https://github.com/bookfere/Ebook-Translator-Calibre" target="_blank" rel="noreferrer">Ebook Translator for Calibre</a></li><li><a href="https://github.com/anantham/LexiconForge" target="_blank" rel="noreferrer">LexiconForge — GitHub</a></li><li><a href="https://github.com/Shirochi-stack/Glossarion" target="_blank" rel="noreferrer">Glossarion — GitHub</a></li><li><a href="https://github.com/YuBing-link/noveltrans" target="_blank" rel="noreferrer">NovelTrans — GitHub</a></li><li><a href="https://github.com/hydropix/TranslateBooksWithLLMs" target="_blank" rel="noreferrer">TranslateBooksWithLLMs — GitHub</a></li><li><a href="https://github.com/Helsinki-NLP/OPUS-CAT" target="_blank" rel="noreferrer">OPUS-CAT — GitHub</a></li><li><a href="https://gitlab.com/sansors/polyglotshelf" target="_blank" rel="noreferrer">PolyglotShelf — GitLab</a></li></ul>',71)])])}const h=t(i,[["render",l]]);export{g as __pageData,h as default};
